#include <iostream>

// -- Simulated first inclusion of mathutils.h --------------------
#ifndef MATHUTILS_H
#define MATHUTILS_H

int add(int a, int b);
int multiply(int a, int b);

#endif // MATHUTILS_H
// ----------------------------------------------------------------

// -- Simulated second inclusion of mathutils.h (guard skips it) --
#ifndef MATHUTILS_H
#define MATHUTILS_H
int add(int a, int b);
int multiply(int a, int b);
#endif // MATHUTILS_H
// ----------------------------------------------------------------

int add(int a, int b) {
    return a + b;
}

int multiply(int a, int b) {
    return a * b;
}

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    std::cout << "add(a, b) = " << add(a, b) << '\n';
    std::cout << "multiply(a, b) = " << multiply(a, b) << '\n';

    return 0;
}
